import java.util.HashMap;
import java.util.Map;
import java.lang.reflect.Method;

public class ConcodeContext {
    // Map of function names to their reflective Method objects
    private Map<String, Method> functions = new HashMap<>();

    // Thread-local evaluator for current execution
    private ThreadLocal<ELEvaluator> current = new ThreadLocal<>();

    // Ambient context and evaluators
    private Context context;
    private ExpressionEvaluator evaluator;

    // Variables stored in this context
    private Map<String, Object> vars = new HashMap<>();

    // Resolve a function by name
    public Method resolveFunction(String name) {
        return functions.get(name);
    }

    // Add or register a function
    public void addFunction(String name, Method method) {
        functions.put(name, method);
    }

    // Resolve a variable value by name
    public Object resolveVariable(String name) {
        return vars.get(name);
    }

    // Set a variable (overwrite by default)
    public void setVariable(String name, Object value) {
        vars.put(name, value);
    }

    // Overloaded setVariable to control overwrite behavior
    public void setVariable(String name, Object value, boolean overwrite) {
        if (overwrite || !vars.containsKey(name)) {
            vars.put(name, value);
        }
    }

    // Get the current ELEvaluator
    public ELEvaluator getCurrent() {
        return current.get();
    }

    // Get a variable (alias for resolveVariable)
    public Object getVariable(String name) {
        return vars.get(name);
    }

    // Get the full context
    public Context getContext() {
        return context;
    }

    // Generic evaluate method (placeholder for real evaluation)
    public <T> T evaluate(T expression) {
        // In a concrete implementation, delegate to evaluator using context/vars
        // Here we return the expression as a placeholder.
        return expression;
    }

    // Optional helpers to set context/evaluator if needed
    public void setContext(Context ctx) {
        this.context = ctx;
    }

    public void setEvaluator(ExpressionEvaluator eval) {
        this.evaluator = eval;
    }

    public ExpressionEvaluator getEvaluator() {
        return evaluator;
    }
}
